## Problem1(3.5.8.100)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$B = non_zero_random(2,5,1)*list_random(-1,1);
$A = $B*non_zero_random(-9,9,1);
$C = $B*non_zero_random(-19,19,1);
Context("Fraction");
$b = Fraction($C,$B);
$m = Fraction(-$A,$B);
Context()->flags->set(reduceConstants=>0);
Context()->variables->are(x=>'Real',y=>'Real');
Context()->noreduce('(-x)-y','(-x)+y');
parser::Assignment->Allow;
$left = Formula("$A x+$B y")->reduce;
$right = Formula("$C")->reduce;
$answer = Formula("y=$m x + $b")->reduce->reduce;
$leftsteps[0] = Formula("$left-$A x")->reduce;
$leftsteps[1] = Formula("$B y")->reduce;
$leftsteps[2] = $leftsteps[1]/Formula("$B");
$leftsteps[3] = Formula("y");
$rightsteps[0] = Formula("$right-$A x")->reduce;
$rightsteps[1] = $rightsteps[0];
$rightsteps[2] = $rightsteps[1]/Formula("$B");
$rightsteps[3] = Formula("$m x + $b")->reduce;

############################################################
# Body
############################################################

BEGIN_PGML
Isolate [`y`] in the standard form linear equation (a topic covered later in this book).

[`[$left]=[$right]`]

[_]{$answer}{20}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION

[```\newcommand{\amp}{&}
\begin{aligned}
[$left] \amp = [$right]\\
[$leftsteps[0]] \amp = [$rightsteps[0]]\\
[$leftsteps[1]] \amp = [$rightsteps[1]]\\
[$leftsteps[2]] \amp = [$rightsteps[2]]\\
[$leftsteps[3]] \amp = [$rightsteps[3]]
\end{aligned}
```]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
